import { RangeSetBuilder } from '@codemirror/state';
import type {
  Decoration,
  DecorationSet,
  EditorView,
  ViewUpdate,
} from '@codemirror/view';
import { ViewPlugin } from '@codemirror/view';

import { escapedCharacterMark } from './decoration-marks.js';
import { ESCAPED_CHARACTERS_REGEX } from '../utils/escape-suggestion.js';

/**
 * Create a range set with decorations for all escaped characters.
 * @internal
 */
export function createEscapedCharacterDecorations(view: EditorView) {
  const builder = new RangeSetBuilder<Decoration>();

  for (const { from, to } of view.visibleRanges) {
    const stringInput = view.state.sliceDoc(from, to);
    const escapedCharacters = stringInput.matchAll(ESCAPED_CHARACTERS_REGEX);

    for (const match of escapedCharacters) {
      const { index } = match;
      // The end index of the decoration needs to be the match's index + 2.
      // -> match index = cursor before '\', +1 = cursor after '\', but still
      // before the escaped character. +2 includes the escaped character.
      builder.add(index, index + 2, escapedCharacterMark);
    }
  }

  return builder.finish();
}

/**
 * View plugin to wrap all escaped characters in spans.
 * @internal
 */
export const EscapedCharacterDecorationPlugin = ViewPlugin.fromClass(
  class {
    decorations: DecorationSet;

    constructor(view: EditorView) {
      this.decorations = createEscapedCharacterDecorations(view);
    }

    update(update: ViewUpdate) {
      if (update.docChanged) {
        this.decorations = createEscapedCharacterDecorations(update.view);
      }
    }
  },
  {
    decorations: (view) => view.decorations,
  },
);
